const aiResponse = $input.item.json.text || $input.item.json.output || '';

const getReviewEntries = () => {
  try {
    const httpRequestData = $('HTTP Request').item.json;
    const entries = Array.isArray(httpRequestData?.feed?.entry) ? httpRequestData.feed.entry : [];

    return entries.filter((entry) => {
      const rating = entry?.['im:rating']?.label || entry?.['im:rating'] || '';
      const reviewId = entry?.id?.label || entry?.id || '';
      return String(rating).trim() !== '' && String(reviewId).trim() !== '';
    });
  } catch (error) {
    console.error('원본 리뷰 데이터 가져오기 실패:', error);
    return [];
  }
};

const originalEntries = getReviewEntries();
if (originalEntries.length === 0) {
  return [];
}

const normalizeJsonString = (rawValue) => {
  const sanitized = (rawValue || '')
    .toString()
    .trim()
    .replace(/```json\s*/gi, '')
    .replace(/```\s*/g, '')
    .trim();

  if (!sanitized) {
    return '';
  }

  const arrayStart = sanitized.indexOf('[');
  const arrayEnd = sanitized.lastIndexOf(']');
  if (arrayStart !== -1 && arrayEnd !== -1 && arrayEnd > arrayStart) {
    return sanitized.slice(arrayStart, arrayEnd + 1);
  }

  return sanitized;
};

let parsedData = [];
try {
  const jsonString = normalizeJsonString(aiResponse);
  parsedData = JSON.parse(jsonString);

  if (!Array.isArray(parsedData)) {
    parsedData = [parsedData];
  }
} catch (error) {
  console.error('JSON 파싱 실패:', error);
  parsedData = [];
}

if (!parsedData.length) {
  return [{
    json: {
      ID: `PARSE_ERROR_${Date.now()}`,
      긴급도: 'ERROR',
      유형: '파싱실패',
      요약: 'No valid data parsed',
      원본: aiResponse.toString().slice(0, 1500),
      별점: '',
      작성자: 'system',
      작성일시: new Date().toISOString()
    }
  }];
}

return originalEntries.map((originalEntry, index) => {
  const item = parsedData[index] || {};

  const originalAuthor = originalEntry.author?.name?.label || originalEntry.author?.name || '';
  const originalDate = originalEntry.updated?.label || originalEntry.updated || '';
  const originalRating = originalEntry['im:rating']?.label || originalEntry['im:rating'] || '';
  const originalContent = originalEntry.content?.label || originalEntry.content || originalEntry.content?.['#text'] || '';
  const originalId = originalEntry.id?.label || originalEntry.id || '';

  return {
    json: {
      priority: item.priority || '✅ Normal',
      category: item.category || '기타',
      summary: item.summary || '분류 결과 없음',
      author: originalAuthor,
      date: originalDate,
      rating: originalRating,
      content: originalContent,
      id: originalId,
      _index: index
    }
  };
});

const normalizeValue = (value) => (value ?? '').toString().trim();

const existingIds = new Set();

try {
  const existingReviews = $('Get Existing Reviews').all();
  if (Array.isArray(existingReviews) && existingReviews.length > 0) {
    existingReviews.forEach((item) => {
      const id = normalizeValue(item.json?.ID || item.json?.id);
      if (id) {
        existingIds.add(id);
      }
    });
  }
} catch (error) {
  console.error('기존 리뷰 데이터 로드 실패:', error.message || error);
}

const currentItems = $input.all();
if (!Array.isArray(currentItems) || currentItems.length === 0) {
  return [];
}

const seenCurrentIds = new Set();
const output = [];

for (const item of currentItems) {
  const row = item.json || {};
  const id = normalizeValue(row.id || row.ID);

  if (!id) {
    continue;
  }

  if (existingIds.has(id) || seenCurrentIds.has(id)) {
    continue;
  }

  seenCurrentIds.add(id);

  const priority = row.priority || row.긴급도 || '';
  const category = row.category || row.유형 || '';
  const summary = row.summary || row.요약 || '';
  const content = row.content || row.원본 || '';
  const rating = row.rating || row.별점 || '';
  const author = row.author || row.작성자 || '';
  const date = row.date || row.작성일시 || '';

  output.push({
    json: {
      ID: id,
      긴급도: priority,
      유형: category,
      요약: summary,
      원본: content,
      별점: rating,
      작성자: author,
      작성일시: date,
      priority,
      category,
      summary,
      content,
      rating,
      author,
      date
    }
  });
}

return output;

const inputItems = $input.all();
if (!Array.isArray(inputItems) || inputItems.length === 0) {
  return [];
}

const asText = (value, fallback = 'N/A') => {
  const normalized = (value ?? '').toString().trim();
  return normalized.length > 0 ? normalized : fallback;
};

const appStoreId = ($env.VOC_APP_ID || '1018769995').toString().trim();
const country = ($env.VOC_APP_COUNTRY || 'kr').toString().trim();
const runId = `RUN_${Date.now()}`;

return inputItems.map(({ json = {} }) => ({
  json: {
    reviewId: asText(json.ID || json.id, `MISSING_ID_${Date.now()}`),
    runId,
    appStoreId,
    country,
    author: asText(json.author || json.작성자, '알 수 없음'),
    rating: asText(json.rating || json.별점),
    date: asText(json.date || json.작성일시),
    content: asText(json.content || json.원본),
    priority: asText(json.priority || json.긴급도),
    category: asText(json.category || json.유형),
    summary: asText(json.summary || json.요약)
  }
}));

